var COURSE_TR_KO = [{day: 1, title: `Selamlaşma ve İlk Nezaket`, title_native: `인사와 첫 예절`, focus: `Seul’e yeni vardığında otelde, kafede veya sokakta temel selamlaşmaları kullanacaksın. Bugün Korece’de kibar konuşmanın ilk adımlarını öğreniyorsun.`, vocab: [{ko: `안녕하세요`, tr: `merhaba`, ipa: `an-nyeong-ha-se-yo`},{ko: `감사합니다`, tr: `teşekkür ederim`, ipa: `gam-sa-ham-ni-da`},{ko: `네`, tr: `evet`, ipa: `ne`},{ko: `아니요`, tr: `hayır`, ipa: `a-ni-yo`},{ko: `죄송합니다`, tr: `özür dilerim`, ipa: `joe-song-ham-ni-da`},{ko: `괜찮아요`, tr: `sorun değil, iyiyim`, ipa: `gwaen-chan-a-yo`},{ko: `저`, tr: `ben, bana`, ipa: `co`},{ko: `당신`, tr: `siz, sen`, ipa: `dang-shin`},{ko: `한국`, tr: `Kore`, ipa: `han-guk`},{ko: `터키`, tr: `Türkiye`, ipa: `teo-ki`}], phrases: [{ko: `안녕하세요.`, tr: `Merhaba.`, ipa: `an-nyeong-ha-se-yo`},{ko: `감사합니다.`, tr: `Teşekkür ederim.`, ipa: `gam-sa-ham-ni-da`},{ko: `죄송합니다.`, tr: `Özür dilerim.`, ipa: `joe-song-ham-ni-da`},{ko: `괜찮아요.`, tr: `Sorun değil.`, ipa: `gwaen-chan-a-yo`},{ko: `네, 감사합니다.`, tr: `Evet, teşekkür ederim.`, ipa: `ne, gam-sa-ham-ni-da`},{ko: `아니요, 괜찮아요.`, tr: `Hayır, sorun değil.`, ipa: `a-ni-yo, gwaen-chan-a-yo`}], grammar: `Korece’de günlük seyahat durumlarında en güvenli form kibar “-요” veya resmi “-습니다/-ㅂ니다” biçimidir. “안녕하세요” hem sabah hem öğleden sonra hem de akşam kullanılabilir. İlk günlerde kısa ve kibar ifadeler kullanmak, yanlış yapma riskini azaltır.`, practice: [`Bir otel görevlisine Korece merhaba de.`,`Bir kafede teşekkür ederken “감사합니다” kullan.`,`Yanlışlıkla birine çarptığını düşün ve özür dile.`,`“Evet, teşekkür ederim” ifadesini yüksek sesle üç kez söyle.`,`“Hayır, sorun değil” cümlesini bir teklif reddederken kullan.`]},{day: 2, title: `Kendini Tanıtma`, title_native: `자기소개`, focus: `Busan’da bir hostelde veya Seul’de bir tur grubunda kendini kısaca tanıtman gerekebilir. Bugün adını, ülkeni ve temel bilgileri söylemeyi öğreneceksin.`, vocab: [{ko: `이름`, tr: `isim`, ipa: `i-reum`},{ko: `저는`, tr: `ben`, ipa: `co-neun`},{ko: `사람`, tr: `kişi, insan`, ipa: `sa-ram`},{ko: `학생`, tr: `öğrenci`, ipa: `hak-saeng`},{ko: `여행자`, tr: `gezgin`, ipa: `yeo-haeng-ja`},{ko: `친구`, tr: `arkadaş`, ipa: `chin-gu`},{ko: `반갑습니다`, tr: `memnun oldum`, ipa: `ban-gap-seum-ni-da`},{ko: `터키 사람`, tr: `Türk kişi`, ipa: `teo-ki sa-ram`},{ko: `한국어`, tr: `Korece`, ipa: `han-gu-geo`},{ko: `조금`, tr: `biraz`, ipa: `jo-geum`}], phrases: [{ko: `저는 지미입니다.`, tr: `Ben Jimmy’yim.`, ipa: `co-neun ji-mi-im-ni-da`},{ko: `저는 터키 사람입니다.`, tr: `Ben Türk’üm.`, ipa: `co-neun teo-ki sa-ram-im-ni-da`},{ko: `저는 여행자입니다.`, tr: `Ben gezginim.`, ipa: `co-neun yeo-haeng-ja-im-ni-da`},{ko: `반갑습니다.`, tr: `Memnun oldum.`, ipa: `ban-gap-seum-ni-da`},{ko: `한국어를 조금 해요.`, tr: `Biraz Korece konuşuyorum.`, ipa: `han-gu-geo-reul jo-geum hae-yo`},{ko: `이름이 뭐예요?`, tr: `Adınız ne?`, ipa: `i-reu-mi mwo-ye-yo`}], grammar: `“저는 ...입니다” kalıbı “Ben ...im” demenin kibar ve güvenli yoludur. Korece’de cümle çoğunlukla özne-nesne-fiil düzenindedir, yani fiil genellikle en sona gelir. Tanışırken “반갑습니다” çok doğal ve nazik bir ifadedir.`, practice: [`Kendi adınla “저는 ...입니다” cümlesi kur.`,`“Ben Türk’üm” cümlesini Korece söyle.`,`Birine adını sormak için “이름이 뭐예요?” de.`,`“Biraz Korece konuşuyorum” ifadesini ezberle.`,`Bir tur grubunda kendini iki cümleyle tanıt.`]},{day: 3, title: `Temel Sorular`, title_native: `기본 질문`, focus: `Kore’de yolculuk ederken kısa sorular sormak çok işine yarar. Bugün “ne, nerede, kim, ne kadar” gibi pratik soru kelimelerini öğreneceksin.`, vocab: [{ko: `뭐`, tr: `ne`, ipa: `mwo`},{ko: `어디`, tr: `nerede`, ipa: `eo-di`},{ko: `누구`, tr: `kim`, ipa: `nu-gu`},{ko: `언제`, tr: `ne zaman`, ipa: `eon-je`},{ko: `얼마`, tr: `ne kadar`, ipa: `eol-ma`},{ko: `왜`, tr: `neden`, ipa: `wae`},{ko: `어떻게`, tr: `nasıl`, ipa: `eo-tteo-ke`},{ko: `화장실`, tr: `tuvalet`, ipa: `hwa-jang-shil`},{ko: `역`, tr: `istasyon`, ipa: `yeok`},{ko: `가게`, tr: `dükkân`, ipa: `ga-ge`}], phrases: [{ko: `이게 뭐예요?`, tr: `Bu nedir?`, ipa: `i-ge mwo-ye-yo`},{ko: `화장실이 어디예요?`, tr: `Tuvalet nerede?`, ipa: `hwa-jang-shi-ri eo-di-ye-yo`},{ko: `역이 어디예요?`, tr: `İstasyon nerede?`, ipa: `yeo-gi eo-di-ye-yo`},{ko: `얼마예요?`, tr: `Ne kadar?`, ipa: `eol-ma-ye-yo`},{ko: `누구예요?`, tr: `Kim?`, ipa: `nu-gu-ye-yo`},{ko: `언제예요?`, tr: `Ne zaman?`, ipa: `eon-je-ye-yo`}], grammar: `Korece’de soru cümleleri çoğu zaman tonlama ve soru kelimesiyle anlaşılır. “예요/이에요” günlük kibar konuşmada “...dır” anlamı verir. “어디예요?” kalıbı, yer sormak için çok kullanışlıdır.`, practice: [`Bir haritaya bakarak “İstasyon nerede?” diye sor.`,`Bilmediğin bir yemeği gösterip “Bu nedir?” de.`,`Bir mağazada fiyat sormak için “얼마예요?” kullan.`,`“Tuvalet nerede?” cümlesini ezberle.`,`Beş soru kelimesini Korece-Türkçe eşleştir.`]},{day: 4, title: `Sayılar ve Fiyatlar`, title_native: `숫자와 가격`, focus: `Myeongdong’da alışveriş yaparken veya pazarda sokak yemeği alırken fiyat anlaman gerekir. Bugün temel Korece sayılar ve para ifadeleri üzerinde duracaksın.`, vocab: [{ko: `일`, tr: `bir`, ipa: `il`},{ko: `이`, tr: `iki`, ipa: `i`},{ko: `삼`, tr: `üç`, ipa: `sam`},{ko: `사`, tr: `dört`, ipa: `sa`},{ko: `오`, tr: `beş`, ipa: `o`},{ko: `육`, tr: `altı`, ipa: `yuk`},{ko: `칠`, tr: `yedi`, ipa: `chil`},{ko: `팔`, tr: `sekiz`, ipa: `pal`},{ko: `구`, tr: `dokuz`, ipa: `gu`},{ko: `십`, tr: `on`, ipa: `ship`}], phrases: [{ko: `천 원이에요.`, tr: `Bin won.`, ipa: `cheon wo-ni-e-yo`},{ko: `오천 원이에요.`, tr: `Beş bin won.`, ipa: `o-cheon wo-ni-e-yo`},{ko: `만원이에요.`, tr: `On bin won.`, ipa: `ma-nwo-ni-e-yo`},{ko: `얼마예요?`, tr: `Ne kadar?`, ipa: `eol-ma-ye-yo`},{ko: `너무 비싸요.`, tr: `Çok pahalı.`, ipa: `neo-mu bi-ssa-yo`},{ko: `조금 깎아 주세요.`, tr: `Biraz indirim yapın lütfen.`, ipa: `jo-geum kka-kka ju-se-yo`}], grammar: `Korece’de para birimi “원” yani won’dur ve sayıdan sonra gelir. “천” bin, “만” on bin anlamına gelir; bu yüzden Kore’de fiyatları anlamak için özellikle “천” ve “만” önemlidir. “주세요” bir şey isterken kullanılan kibar “lütfen verin/yapın” kalıbıdır.`, practice: [`1’den 10’a kadar Korece say.`,`“Beş bin won” ifadesini Korece söyle.`,`Bir pazarda fiyat soran kısa bir cümle kur.`,`“Çok pahalı” ifadesini doğal tonla söyle.`,`Üç farklı fiyatı Korece okumaya çalış.`]},{day: 5, title: `Günlük Nezaket ve Rica`, title_native: `일상 예절과 부탁`, focus: `Kore’de kibar rica ifadeleri özellikle restoran, otel ve mağaza ortamlarında çok önemlidir. Bugün “lütfen”, “yardım edin”, “bir dakika” gibi ifadeleri öğreneceksin.`, vocab: [{ko: `주세요`, tr: `lütfen verin`, ipa: `ju-se-yo`},{ko: `도와주세요`, tr: `yardım edin lütfen`, ipa: `do-wa-ju-se-yo`},{ko: `잠깐만요`, tr: `bir dakika`, ipa: `jam-kkan-man-yo`},{ko: `미안해요`, tr: `üzgünüm, pardon`, ipa: `mi-an-hae-yo`},{ko: `실례합니다`, tr: `affedersiniz`, ipa: `shil-lye-ham-ni-da`},{ko: `부탁해요`, tr: `rica ederim, lütfen`, ipa: `bu-ta-kae-yo`},{ko: `천천히`, tr: `yavaşça`, ipa: `cheon-cheon-hi`},{ko: `다시`, tr: `tekrar`, ipa: `da-shi`},{ko: `말하다`, tr: `söylemek`, ipa: `mal-ha-da`},{ko: `듣다`, tr: `dinlemek`, ipa: `deut-da`}], phrases: [{ko: `실례합니다.`, tr: `Affedersiniz.`, ipa: `shil-lye-ham-ni-da`},{ko: `도와주세요.`, tr: `Yardım edin lütfen.`, ipa: `do-wa-ju-se-yo`},{ko: `잠깐만요.`, tr: `Bir dakika lütfen.`, ipa: `jam-kkan-man-yo`},{ko: `다시 말해 주세요.`, tr: `Tekrar söyleyin lütfen.`, ipa: `da-shi ma-rae ju-se-yo`},{ko: `천천히 말해 주세요.`, tr: `Yavaş konuşun lütfen.`, ipa: `cheon-cheon-hi ma-rae ju-se-yo`},{ko: `부탁해요.`, tr: `Rica ederim.`, ipa: `bu-ta-kae-yo`}], grammar: `“주세요” tek başına veya fiillerle birlikte rica anlamı verir. “말해 주세요” “söyleyin lütfen”, “도와주세요” ise “yardım edin lütfen” demektir. Kore’de yabancı biri olarak anlamadığında “천천히 말해 주세요” demek çok doğal ve naziktir.`, practice: [`Birinden yavaş konuşmasını iste.`,`Kalabalık metroda birine “Affedersiniz” de.`,`Bir görevliden yardım isteme cümlesi kur.`,`“Tekrar söyleyin lütfen” ifadesini ezberle.`,`“잠깐만요” ifadesini üç farklı durumda kullanmayı düşün.`]},{day: 6, title: `Havalimanında`, title_native: `공항에서`, focus: `Incheon Havalimanı’na indiğinde pasaport kontrolü, bagaj ve çıkış tabelalarıyla karşılaşırsın. Bugün havalimanında en çok gereken kelimeleri ve cümleleri öğreneceksin.`, vocab: [{ko: `공항`, tr: `havalimanı`, ipa: `gong-hang`},{ko: `여권`, tr: `pasaport`, ipa: `yeo-kkwon`},{ko: `비행기`, tr: `uçak`, ipa: `bi-haeng-gi`},{ko: `짐`, tr: `bagaj`, ipa: `jim`},{ko: `수하물`, tr: `valiz, bagaj`, ipa: `su-ha-mul`},{ko: `출구`, tr: `çıkış`, ipa: `chul-gu`},{ko: `입국`, tr: `ülkeye giriş`, ipa: `ip-guk`},{ko: `세관`, tr: `gümrük`, ipa: `se-gwan`},{ko: `표`, tr: `bilet`, ipa: `pyo`},{ko: `도착`, tr: `varış`, ipa: `do-chak`}], phrases: [{ko: `여권 여기 있습니다.`, tr: `Pasaport burada.`, ipa: `yeo-kkwon yeo-gi it-seum-ni-da`},{ko: `짐은 어디예요?`, tr: `Bagaj nerede?`, ipa: `ji-meun eo-di-ye-yo`},{ko: `출구가 어디예요?`, tr: `Çıkış nerede?`, ipa: `chul-gu-ga eo-di-ye-yo`},{ko: `택시는 어디예요?`, tr: `Taksi nerede?`, ipa: `taek-shi-neun eo-di-ye-yo`},{ko: `저는 관광객입니다.`, tr: `Ben turistim.`, ipa: `co-neun gwan-gwang-gaek-im-ni-da`},{ko: `서울에 갑니다.`, tr: `Seul’e gidiyorum.`, ipa: `seo-u-re gam-ni-da`}], grammar: `“에 갑니다” bir yere gitmeyi ifade eder: “서울에 갑니다” Seul’e gidiyorum demektir. “여기 있습니다” “burada var/burada” anlamındadır ve belge gösterirken çok kullanışlıdır. Resmi ortamlarda “-습니다/-ㅂ니다” kullanmak daha güvenli ve saygılıdır.`, practice: [`Pasaport kontrolünde kendini turist olarak tanıt.`,`Bagajın nerede olduğunu sor.`,`“Seul’e gidiyorum” cümlesini söyle.`,`Havalimanında çıkış yönünü sor.`,`“Pasaport burada” ifadesini rol yaparak kullan.`]},{day: 7, title: `Otobüs, Metro ve Taksi`, title_native: `버스, 지하철, 택시`, focus: `Seul ve Busan’da toplu taşıma hızlı ve yaygındır. Bugün metro, otobüs ve taksi kullanırken soracağın temel cümleleri öğreneceksin.`, vocab: [{ko: `버스`, tr: `otobüs`, ipa: `beo-seu`},{ko: `지하철`, tr: `metro`, ipa: `ji-ha-cheol`},{ko: `택시`, tr: `taksi`, ipa: `taek-shi`},{ko: `역`, tr: `istasyon`, ipa: `yeok`},{ko: `정류장`, tr: `durak`, ipa: `jeong-nyu-jang`},{ko: `카드`, tr: `kart`, ipa: `ka-deu`},{ko: `교통카드`, tr: `ulaşım kartı`, ipa: `gyo-tong-ka-deu`},{ko: `노선`, tr: `hat, rota`, ipa: `no-seon`},{ko: `갈아타다`, tr: `aktarma yapmak`, ipa: `ga-ra-ta-da`},{ko: `도착하다`, tr: `varmak`, ipa: `do-cha-ka-da`}], phrases: [{ko: `지하철역이 어디예요?`, tr: `Metro istasyonu nerede?`, ipa: `ji-ha-cheol-yeo-gi eo-di-ye-yo`},{ko: `이 버스는 서울역에 가요?`, tr: `Bu otobüs Seul İstasyonu’na gider mi?`, ipa: `i beo-seu-neun seo-ul-yeo-ge ga-yo`},{ko: `택시 타고 싶어요.`, tr: `Taksiye binmek istiyorum.`, ipa: `taek-shi ta-go shi-peo-yo`},{ko: `여기로 가 주세요.`, tr: `Buraya gidin lütfen.`, ipa: `yeo-gi-ro ga ju-se-yo`},{ko: `교통카드 있어요?`, tr: `Ulaşım kartı var mı?`, ipa: `gyo-tong-ka-deu i-sseo-yo`},{ko: `어디에서 갈아타요?`, tr: `Nerede aktarma yapıyorum?`, ipa: `eo-di-e-seo ga-ra-ta-yo`}], grammar: `“가요?” bir yere gidip gitmediğini sormak için çok pratik bir kalıptır. “여기로” “buraya doğru” anlamı verir ve takside harita gösterirken işe yarar. “타다” binmek fiilidir; “택시 타고 싶어요” taksiye binmek istiyorum demektir.`, practice: [`Bir otobüsün Seul İstasyonu’na gidip gitmediğini sor.`,`Harita göstererek “Buraya gidin lütfen” de.`,`Metroda nerede aktarma yapacağını sor.`,`Ulaşım kartı olup olmadığını sor.`,`“Taksiye binmek istiyorum” cümlesini ezberle.`]},{day: 8, title: `Otelde Konaklama`, title_native: `호텔 숙박`, focus: `Jeju’da veya Seul’de otele giriş yaparken rezervasyon, oda ve kimlik bilgileri gerekir. Bugün otel resepsiyonunda kullanacağın Koreceyi öğreneceksin.`, vocab: [{ko: `호텔`, tr: `otel`, ipa: `ho-tel`},{ko: `예약`, tr: `rezervasyon`, ipa: `ye-yak`},{ko: `방`, tr: `oda`, ipa: `bang`},{ko: `열쇠`, tr: `anahtar`, ipa: `yeol-soe`},{ko: `카드키`, tr: `kart anahtar`, ipa: `ka-deu-ki`},{ko: `체크인`, tr: `check-in`, ipa: `che-keu-in`},{ko: `체크아웃`, tr: `check-out`, ipa: `che-keu-a-ut`},{ko: `하룻밤`, tr: `bir gece`, ipa: `ha-rut-ppam`},{ko: `침대`, tr: `yatak`, ipa: `chim-dae`},{ko: `조식`, tr: `kahvaltı`, ipa: `jo-shik`}], phrases: [{ko: `예약했어요.`, tr: `Rezervasyon yaptım.`, ipa: `ye-ya-kae-sseo-yo`},{ko: `체크인하고 싶어요.`, tr: `Check-in yapmak istiyorum.`, ipa: `che-keu-in-ha-go shi-peo-yo`},{ko: `제 이름은 지미입니다.`, tr: `Benim adım Jimmy.`, ipa: `je i-reu-meun ji-mi-im-ni-da`},{ko: `방 키 주세요.`, tr: `Oda anahtarı lütfen.`, ipa: `bang ki ju-se-yo`},{ko: `조식이 포함돼요?`, tr: `Kahvaltı dahil mi?`, ipa: `jo-shi-gi po-ham-dwae-yo`},{ko: `체크아웃은 몇 시예요?`, tr: `Check-out saat kaçta?`, ipa: `che-keu-a-u-seun myeot shi-ye-yo`}], grammar: `“하고 싶어요” “yapmak istiyorum” anlamına gelir ve seyahatte çok kullanılır. “예약했어요” geçmiş zamanda “rezervasyon yaptım” demektir. Kore otellerinde kahvaltı için “조식” kelimesi sık geçer.`, practice: [`Resepsiyonda rezervasyon yaptığını söyle.`,`Check-in yapmak istediğini belirt.`,`Kahvaltının dahil olup olmadığını sor.`,`Check-out saatini sor.`,`Kendi adınla “Benim adım ...” cümlesi kur.`]},{day: 9, title: `Yön Sorma`, title_native: `길 묻기`, focus: `Hongdae, Insadong veya Busan sahilinde yürürken yön sormak gerekebilir. Bugün sağ, sol, düz gitmek ve yakınlık ifadelerini öğreneceksin.`, vocab: [{ko: `길`, tr: `yol`, ipa: `gil`},{ko: `오른쪽`, tr: `sağ taraf`, ipa: `o-reun-jjok`},{ko: `왼쪽`, tr: `sol taraf`, ipa: `wen-jjok`},{ko: `똑바로`, tr: `düz`, ipa: `ttok-ba-ro`},{ko: `근처`, tr: `yakın çevre`, ipa: `geun-cheo`},{ko: `앞`, tr: `ön`, ipa: `ap`},{ko: `뒤`, tr: `arka`, ipa: `dwi`},{ko: `옆`, tr: `yan`, ipa: `yeop`},{ko: `지도`, tr: `harita`, ipa: `ji-do`},{ko: `멀다`, tr: `uzak olmak`, ipa: `meol-da`}], phrases: [{ko: `길을 잃었어요.`, tr: `Yolumu kaybettim.`, ipa: `gi-reul i-reo-sseo-yo`},{ko: `여기가 어디예요?`, tr: `Burası neresi?`, ipa: `yeo-gi-ga eo-di-ye-yo`},{ko: `오른쪽으로 가세요.`, tr: `Sağa gidin.`, ipa: `o-reun-jjo-geu-ro ga-se-yo`},{ko: `왼쪽으로 가세요.`, tr: `Sola gidin.`, ipa: `wen-jjo-geu-ro ga-se-yo`},{ko: `똑바로 가세요.`, tr: `Düz gidin.`, ipa: `ttok-ba-ro ga-se-yo`},{ko: `근처에 있어요?`, tr: `Yakında mı?`, ipa: `geun-cheo-e i-sseo-yo`}], grammar: `“으로/로” yön bildirir; “오른쪽으로” sağa doğru, “왼쪽으로” sola doğru demektir. “있어요?” bir şeyin var olup olmadığını veya bir yerde bulunup bulunmadığını sormak için kullanılır. “길을 잃었어요” turistler için çok yararlı bir acil durum cümlesidir.`, practice: [`“Yolumu kaybettim” cümlesini söyle.`,`Bir müzenin yakında olup olmadığını sor.`,`Sağ, sol ve düz kelimelerini jestlerle çalış.`,`Haritayı gösterip “Burası neresi?” diye sor.`,`Birine metro istasyonuna nasıl gidileceğini sorduğunu hayal et.`]},{day: 10, title: `Kafede Sipariş`, title_native: `카페에서 주문하기`, focus: `Kore’de kafeler çok yaygındır; Seul’de neredeyse her mahallede farklı konsept kafeler bulursun. Bugün kahve, çay ve basit sipariş ifadelerini öğreneceksin.`, vocab: [{ko: `카페`, tr: `kafe`, ipa: `ka-pe`},{ko: `커피`, tr: `kahve`, ipa: `keo-pi`},{ko: `아메리카노`, tr: `Americano`, ipa: `a-me-ri-ka-no`},{ko: `라떼`, tr: `latte`, ipa: `ra-tte`},{ko: `차`, tr: `çay`, ipa: `cha`},{ko: `물`, tr: `su`, ipa: `mul`},{ko: `뜨거운`, tr: `sıcak`, ipa: `tteu-geo-un`},{ko: `차가운`, tr: `soğuk`, ipa: `cha-ga-un`},{ko: `컵`, tr: `bardak`, ipa: `keop`},{ko: `설탕`, tr: `şeker`, ipa: `seol-tang`}], phrases: [{ko: `아메리카노 하나 주세요.`, tr: `Bir Americano lütfen.`, ipa: `a-me-ri-ka-no ha-na ju-se-yo`},{ko: `아이스 라떼 주세요.`, tr: `Buzlu latte lütfen.`, ipa: `a-i-seu ra-tte ju-se-yo`},{ko: `따뜻한 커피 있어요?`, tr: `Sıcak kahve var mı?`, ipa: `tta-tteu-tan keo-pi i-sseo-yo`},{ko: `물 주세요.`, tr: `Su lütfen.`, ipa: `mul ju-se-yo`},{ko: `포장해 주세요.`, tr: `Paket yapın lütfen.`, ipa: `po-jang-hae ju-se-yo`},{ko: `여기서 마실게요.`, tr: `Burada içeceğim.`, ipa: `yeo-gi-seo ma-shil-ge-yo`}], grammar: `Korece’de sipariş verirken sayıdan sonra “주세요” kullanmak çok doğaldır: “하나 주세요” bir tane lütfen. “여기서” burada, “포장” ise paket anlamına gelir. Kafelerde “아이스” buzlu içecekler için çok sık kullanılır.`, practice: [`Bir Americano siparişi ver.`,`Buzlu latte istediğini söyle.`,`İçeri oturacağını belirt.`,`Paket servis iste.`,`Su istemek için kısa ve kibar bir cümle kur.`]},{day: 11, title: `Restoranda Yemek`, title_native: `식당에서 식사하기`, focus: `Kore restoranlarında yemek sipariş etmek bazen hızlı ilerler, bu yüzden kısa ve net ifadeler önemlidir. Bugün menü, yemek, hesap ve temel istekleri öğreneceksin.`, vocab: [{ko: `식당`, tr: `restoran`, ipa: `shik-dang`},{ko: `메뉴`, tr: `menü`, ipa: `me-nyu`},{ko: `음식`, tr: `yemek`, ipa: `eum-shik`},{ko: `밥`, tr: `pirinç, yemek`, ipa: `bap`},{ko: `고기`, tr: `et`, ipa: `go-gi`},{ko: `생선`, tr: `balık`, ipa: `saeng-seon`},{ko: `야채`, tr: `sebze`, ipa: `ya-chae`},{ko: `매운`, tr: `acı`, ipa: `mae-un`},{ko: `계산`, tr: `hesap`, ipa: `gye-san`},{ko: `맛있어요`, tr: `lezzetli`, ipa: `ma-shi-sseo-yo`}], phrases: [{ko: `메뉴 주세요.`, tr: `Menü lütfen.`, ipa: `me-nyu ju-se-yo`},{ko: `이거 주세요.`, tr: `Bundan lütfen.`, ipa: `i-geo ju-se-yo`},{ko: `맵지 않게 해 주세요.`, tr: `Acı olmasın lütfen.`, ipa: `maep-ji an-ke hae ju-se-yo`},{ko: `물 좀 주세요.`, tr: `Biraz su lütfen.`, ipa: `mul jom ju-se-yo`},{ko: `계산해 주세요.`, tr: `Hesap lütfen.`, ipa: `gye-san-hae ju-se-yo`},{ko: `맛있어요.`, tr: `Lezzetli.`, ipa: `ma-shi-sseo-yo`}], grammar: `“이거” “bu şey” anlamındadır ve menüde göstererek sipariş verirken çok işe yarar. “좀” kelimesi ricayı yumuşatır; “물 좀 주세요” kulağa daha doğal gelir. Kore yemekleri acı olabilir, bu yüzden “맵지 않게 해 주세요” çok kullanışlıdır.`, practice: [`Menü isteme cümlesi kur.`,`Menüde bir yemeği gösterip sipariş ver.`,`Yemeğin çok acı olmamasını iste.`,`Hesap istemeyi çalış.`,`“Lezzetli” diyerek garsona teşekkür et.`]},{day: 12, title: `Kore Yemekleri ve Tercihler`, title_native: `한국 음식과 취향`, focus: `Gwangjang Pazarı veya Jeonju’da yerel yemekleri denerken damak tadını açıklaman gerekebilir. Bugün sevdiğin, sevmediğin ve yiyemediğin şeyleri söylemeyi öğreneceksin.`, vocab: [{ko: `김치`, tr: `kimchi`, ipa: `gim-chi`},{ko: `불고기`, tr: `bulgogi`, ipa: `bul-go-gi`},{ko: `비빔밥`, tr: `bibimbap`, ipa: `bi-bim-bap`},{ko: `떡볶이`, tr: `tteokbokki`, ipa: `tteok-bok-ki`},{ko: `라면`, tr: `ramen`, ipa: `ra-myeon`},{ko: `좋아하다`, tr: `sevmek`, ipa: `jo-a-ha-da`},{ko: `싫어하다`, tr: `sevmemek`, ipa: `shi-reo-ha-da`},{ko: `못 먹다`, tr: `yiyememek`, ipa: `mot meok-da`},{ko: `알레르기`, tr: `alerji`, ipa: `al-le-reu-gi`},{ko: `채식`, tr: `vejetaryenlik`, ipa: `chae-shik`}], phrases: [{ko: `김치를 좋아해요.`, tr: `Kimchi seviyorum.`, ipa: `gim-chi-reul jo-a-hae-yo`},{ko: `매운 음식을 못 먹어요.`, tr: `Acı yemek yiyemem.`, ipa: `mae-un eum-shi-geul mot meo-geo-yo`},{ko: `고기 안 먹어요.`, tr: `Et yemiyorum.`, ipa: `go-gi an meo-geo-yo`},{ko: `알레르기가 있어요.`, tr: `Alerjim var.`, ipa: `al-le-reu-gi-ga i-sseo-yo`},{ko: `채식 메뉴 있어요?`, tr: `Vejetaryen menü var mı?`, ipa: `chae-shik me-nyu i-sseo-yo`},{ko: `추천해 주세요.`, tr: `Tavsiye edin lütfen.`, ipa: `chu-cheon-hae ju-se-yo`}], grammar: `“안” fiilden önce gelerek olumsuzluk yapar: “안 먹어요” yemiyorum. “못” ise yapamamak anlamı verir: “못 먹어요” yiyemem. Restoranda sağlık veya diyet nedeniyle “알레르기가 있어요” demek çok önemlidir.`, practice: [`Sevdiğin bir Kore yemeğini söyle.`,`Acı yemek yiyemediğini ifade et.`,`Vejetaryen menü sor.`,`Garsondan tavsiye iste.`,`Alerjin olduğunu belirten kısa bir cümle kur.`]},{day: 13, title: `Alışveriş ve Mağazalar`, title_native: `쇼핑과 가게`, focus: `Myeongdong, Dongdaemun veya küçük butiklerde alışveriş yaparken beden, renk ve fiyat soruları gerekir. Bugün mağazada kullanılacak temel ifadeleri öğreneceksin.`, vocab: [{ko: `쇼핑`, tr: `alışveriş`, ipa: `syo-ping`},{ko: `옷`, tr: `kıyafet`, ipa: `ot`},{ko: `신발`, tr: `ayakkabı`, ipa: `shin-bal`},{ko: `가방`, tr: `çanta`, ipa: `ga-bang`},{ko: `색깔`, tr: `renk`, ipa: `saek-kkal`},{ko: `크기`, tr: `beden, boyut`, ipa: `keu-gi`},{ko: `작아요`, tr: `küçük`, ipa: `ja-ga-yo`},{ko: `커요`, tr: `büyük`, ipa: `keo-yo`},{ko: `입어 보다`, tr: `denemek`, ipa: `i-beo bo-da`},{ko: `사다`, tr: `satın almak`, ipa: `sa-da`}], phrases: [{ko: `이거 얼마예요?`, tr: `Bu ne kadar?`, ipa: `i-geo eol-ma-ye-yo`},{ko: `다른 색 있어요?`, tr: `Başka renk var mı?`, ipa: `da-reun saek i-sseo-yo`},{ko: `큰 사이즈 있어요?`, tr: `Büyük beden var mı?`, ipa: `keun sa-i-jeu i-sseo-yo`},{ko: `작은 사이즈 있어요?`, tr: `Küçük beden var mı?`, ipa: `ja-geun sa-i-jeu i-sseo-yo`},{ko: `입어 봐도 돼요?`, tr: `Deneyebilir miyim?`, ipa: `i-beo bwa-do dwae-yo`},{ko: `이거 살게요.`, tr: `Bunu alacağım.`, ipa: `i-geo sal-ge-yo`}], grammar: `“도 돼요?” izin istemek için kullanılır: “입어 봐도 돼요?” Deneyebilir miyim? “다른” başka anlamına gelir ve renk, beden veya model sorarken çok işe yarar. “살게요” karar verip satın alacağını ifade eder.`, practice: [`Bir ceketin fiyatını sor.`,`Başka renk olup olmadığını sor.`,`Büyük beden iste.`,`Bir ürünü denemek için izin iste.`,`“Bunu alacağım” cümlesini alışveriş rolünde kullan.`]},{day: 14, title: `Pazarlık ve Ödeme`, title_native: `흥정과 결제`, focus: `Geleneksel pazarlarda veya küçük dükkânlarda ödeme şekli, nakit ve kart soruları önemlidir. Bugün ödeme ve basit pazarlık ifadelerini öğreneceksin.`, vocab: [{ko: `현금`, tr: `nakit`, ipa: `hyeon-geum`},{ko: `카드`, tr: `kart`, ipa: `ka-deu`},{ko: `결제`, tr: `ödeme`, ipa: `gyeol-je`},{ko: `영수증`, tr: `fiş`, ipa: `yeong-su-jeung`},{ko: `할인`, tr: `indirim`, ipa: `ha-rin`},{ko: `비싸요`, tr: `pahalı`, ipa: `bi-ssa-yo`},{ko: `싸요`, tr: `ucuz`, ipa: `ssa-yo`},{ko: `가격`, tr: `fiyat`, ipa: `ga-gyeok`},{ko: `시장`, tr: `pazar`, ipa: `shi-jang`},{ko: `봉투`, tr: `poşet`, ipa: `bong-tu`}], phrases: [{ko: `카드 돼요?`, tr: `Kart geçiyor mu?`, ipa: `ka-deu dwae-yo`},{ko: `현금으로 낼게요.`, tr: `Nakit ödeyeceğim.`, ipa: `hyeon-geu-meu-ro nael-ge-yo`},{ko: `영수증 주세요.`, tr: `Fiş lütfen.`, ipa: `yeong-su-jeung ju-se-yo`},{ko: `할인돼요?`, tr: `İndirim olur mu?`, ipa: `ha-rin-dwae-yo`},{ko: `조금 비싸요.`, tr: `Biraz pahalı.`, ipa: `jo-geum bi-ssa-yo`},{ko: `봉투 주세요.`, tr: `Poşet lütfen.`, ipa: `bong-tu ju-se-yo`}], grammar: `“으로/로” ödeme yöntemi belirtirken de kullanılır: “현금으로” nakitle. “돼요?” bir şeyin mümkün olup olmadığını sorar; “카드 돼요?” kart olur mu demektir. Pazar yerlerinde kısa ve gülümseyerek konuşmak daha doğal hissettirir.`, practice: [`Kart geçip geçmediğini sor.`,`Nakit ödeyeceğini söyle.`,`Fiş iste.`,`Kibarca indirim sor.`,`Poşet istemek için cümle kur.`]},{day: 15, title: `Zaman ve Saat`, title_native: `시간과 시계`, focus: `Tren, müze, restoran rezervasyonu ve buluşmalar için saat sormak gerekir. Bugün saat, gün ve zaman ifadelerini öğreniyorsun.`, vocab: [{ko: `시간`, tr: `zaman, saat`, ipa: `shi-gan`},{ko: `시`, tr: `saat`, ipa: `shi`},{ko: `분`, tr: `dakika`, ipa: `bun`},{ko: `오늘`, tr: `bugün`, ipa: `o-neul`},{ko: `내일`, tr: `yarın`, ipa: `nae-il`},{ko: `어제`, tr: `dün`, ipa: `eo-je`},{ko: `아침`, tr: `sabah`, ipa: `a-chim`},{ko: `점심`, tr: `öğle`, ipa: `jeom-shim`},{ko: `저녁`, tr: `akşam`, ipa: `jeo-nyeok`},{ko: `밤`, tr: `gece`, ipa: `bam`}], phrases: [{ko: `지금 몇 시예요?`, tr: `Şimdi saat kaç?`, ipa: `ji-geum myeot shi-ye-yo`},{ko: `세 시예요.`, tr: `Saat üç.`, ipa: `se shi-ye-yo`},{ko: `열 시 반이에요.`, tr: `Saat on buçuk.`, ipa: `yeol shi ba-ni-e-yo`},{ko: `내일 만나요.`, tr: `Yarın görüşürüz.`, ipa: `nae-il man-na-yo`},{ko: `오늘 시간이 있어요?`, tr: `Bugün zamanınız var mı?`, ipa: `o-neul shi-ga-ni i-sseo-yo`},{ko: `몇 시에 열어요?`, tr: `Saat kaçta açılıyor?`, ipa: `myeot shi-e yeo-reo-yo`}], grammar: `Korece’de saat söylerken yerli Kore sayıları sık kullanılır, fakat başlangıçta kalıpları ezberlemek yeterlidir. “몇 시” saat kaç anlamına gelir. “에” zamanla birlikte kullanıldığında “-de/-da” anlamı verir: “세 시에” saat üçte.`, practice: [`Saatin kaç olduğunu sor.`,`Bir müzenin saat kaçta açıldığını sor.`,`“Yarın görüşürüz” cümlesini söyle.`,`Bugün, yarın ve dün kelimelerini ezberle.`,`Üç farklı saat ifadesi oluştur.`]},{day: 16, title: `Günler ve Plan Yapma`, title_native: `요일과 계획 세우기`, focus: `Kore’de tur, restoran rezervasyonu veya arkadaş buluşması planlarken günleri bilmek gerekir. Bugün haftanın günleri ve plan kurma ifadelerini öğreneceksin.`, vocab: [{ko: `월요일`, tr: `pazartesi`, ipa: `wo-ryo-il`},{ko: `화요일`, tr: `salı`, ipa: `hwa-yo-il`},{ko: `수요일`, tr: `çarşamba`, ipa: `su-yo-il`},{ko: `목요일`, tr: `perşembe`, ipa: `mo-gyo-il`},{ko: `금요일`, tr: `cuma`, ipa: `geu-myo-il`},{ko: `토요일`, tr: `cumartesi`, ipa: `to-yo-il`},{ko: `일요일`, tr: `pazar`, ipa: `i-ryo-il`},{ko: `이번 주`, tr: `bu hafta`, ipa: `i-beon ju`},{ko: `다음 주`, tr: `gelecek hafta`, ipa: `da-eum ju`},{ko: `예약하다`, tr: `rezervasyon yapmak`, ipa: `ye-ya-ka-da`}], phrases: [{ko: `월요일에 갈게요.`, tr: `Pazartesi gideceğim.`, ipa: `wo-ryo-i-re gal-ge-yo`},{ko: `토요일에 예약하고 싶어요.`, tr: `Cumartesi rezervasyon yapmak istiyorum.`, ipa: `to-yo-i-re ye-yak-ha-go shi-peo-yo`},{ko: `이번 주에 시간이 있어요?`, tr: `Bu hafta zamanınız var mı?`, ipa: `i-beon ju-e shi-ga-ni i-sseo-yo`},{ko: `다음 주에 만나요.`, tr: `Gelecek hafta görüşelim.`, ipa: `da-eum ju-e man-na-yo`},{ko: `오늘은 안 돼요.`, tr: `Bugün olmaz.`, ipa: `o-neu-reun an dwae-yo`},{ko: `금요일은 괜찮아요.`, tr: `Cuma uygun.`, ipa: `geu-myo-i-reun gwaen-chan-a-yo`}], grammar: `Günlerden sonra “에” kullanarak zamanı belirtirsin: “금요일에” cuma günü. “갈게요” konuşanın niyetini ve kararını bildirir. “안 돼요” bir şeyin mümkün olmadığını söyler; plan yaparken çok kullanılır.`, practice: [`Haftanın günlerini sırayla oku.`,`Cumartesi rezervasyon yapmak istediğini söyle.`,`Bugün uygun olmadığını belirt.`,`Cuma gününün uygun olduğunu söyle.`,`Gelecek hafta görüşmeyi teklif et.`]},{day: 17, title: `Sağlık ve Eczane`, title_native: `건강과 약국`, focus: `Seyahatte baş ağrısı, mide rahatsızlığı veya alerji gibi durumlarda eczaneye gitmek gerekebilir. Bugün eczanede güvenle kullanabileceğin ifadeleri öğreneceksin.`, vocab: [{ko: `약국`, tr: `eczane`, ipa: `yak-guk`},{ko: `약`, tr: `ilaç`, ipa: `yak`},{ko: `머리`, tr: `baş`, ipa: `meo-ri`},{ko: `배`, tr: `karın`, ipa: `bae`},{ko: `아프다`, tr: `ağrımak`, ipa: `a-peu-da`},{ko: `열`, tr: `ateş`, ipa: `yeol`},{ko: `감기`, tr: `soğuk algınlığı`, ipa: `gam-gi`},{ko: `기침`, tr: `öksürük`, ipa: `gi-chim`},{ko: `알레르기`, tr: `alerji`, ipa: `al-le-reu-gi`},{ko: `병원`, tr: `hastane`, ipa: `byeong-won`}], phrases: [{ko: `약국이 어디예요?`, tr: `Eczane nerede?`, ipa: `yak-gu-gi eo-di-ye-yo`},{ko: `머리가 아파요.`, tr: `Başım ağrıyor.`, ipa: `meo-ri-ga a-pa-yo`},{ko: `배가 아파요.`, tr: `Karnım ağrıyor.`, ipa: `bae-ga a-pa-yo`},{ko: `감기약 주세요.`, tr: `Soğuk algınlığı ilacı lütfen.`, ipa: `gam-gi-yak ju-se-yo`},{ko: `알레르기가 있어요.`, tr: `Alerjim var.`, ipa: `al-le-reu-gi-ga i-sseo-yo`},{ko: `병원에 가야 해요.`, tr: `Hastaneye gitmeliyim.`, ipa: `byeong-wo-ne ga-ya hae-yo`}], grammar: `“아파요” ağrıyor veya hastayım anlamında kullanılır. Vücut bölümünden sonra “가/이” gelir: “머리가 아파요” başım ağrıyor. “가야 해요” zorunluluk bildirir: gitmeliyim.`, practice: [`Başının ağrıdığını söyle.`,`Eczanenin nerede olduğunu sor.`,`Soğuk algınlığı ilacı iste.`,`Alerjin olduğunu belirt.`,`Hastaneye gitmen gerektiğini söyle.`]},{day: 18, title: `Acil Durumlar`, title_native: `긴급 상황`, focus: `Kaybolma, hırsızlık veya sağlık acili gibi durumlarda kısa ve net Korece hayat kurtarabilir. Bugün acil durumlarda kullanacağın ifadeleri öğreneceksin.`, vocab: [{ko: `도와주세요`, tr: `yardım edin`, ipa: `do-wa-ju-se-yo`},{ko: `경찰`, tr: `polis`, ipa: `gyeong-chal`},{ko: `소방서`, tr: `itfaiye`, ipa: `so-bang-seo`},{ko: `응급실`, tr: `acil servis`, ipa: `eung-geup-shil`},{ko: `사고`, tr: `kaza`, ipa: `sa-go`},{ko: `도난`, tr: `hırsızlık`, ipa: `do-nan`},{ko: `잃어버리다`, tr: `kaybetmek`, ipa: `i-reo-beo-ri-da`},{ko: `위험해요`, tr: `tehlikeli`, ipa: `wi-heom-hae-yo`},{ko: `빨리`, tr: `hızlı`, ipa: `ppal-li`},{ko: `전화`, tr: `telefon`, ipa: `jeon-hwa`}], phrases: [{ko: `도와주세요!`, tr: `Yardım edin!`, ipa: `do-wa-ju-se-yo`},{ko: `경찰을 불러 주세요.`, tr: `Polisi çağırın lütfen.`, ipa: `gyeong-cha-reul bul-leo ju-se-yo`},{ko: `응급실에 가야 해요.`, tr: `Acil servise gitmeliyim.`, ipa: `eung-geup-shi-re ga-ya hae-yo`},{ko: `지갑을 잃어버렸어요.`, tr: `Cüzdanımı kaybettim.`, ipa: `ji-ga-beul i-reo-beo-ryeo-sseo-yo`},{ko: `전화해 주세요.`, tr: `Telefon edin lütfen.`, ipa: `jeon-hwa-hae ju-se-yo`},{ko: `위험해요.`, tr: `Tehlikeli.`, ipa: `wi-heom-hae-yo`}], grammar: `Acil durumda uzun cümleler kurmaya gerek yoktur; “도와주세요” tek başına çok etkilidir. “을/를” nesne ekidir; “경찰을” polisi, “지갑을” cüzdanı anlamı verir. Kaybolan şeyler için “잃어버렸어요” kullanılır.`, practice: [`Yardım istemeyi yüksek sesle çalış.`,`Polisi çağırmalarını iste.`,`Cüzdanını kaybettiğini söyle.`,`Acil servise gitmen gerektiğini belirt.`,`“Tehlikeli” kelimesini hızlıca tanıyacak şekilde ezberle.`]},{day: 19, title: `Telefon ve İnternet`, title_native: `전화와 인터넷`, focus: `Kore’de SIM kart, Wi-Fi ve harita uygulamaları seyahati çok kolaylaştırır. Bugün telefon, internet ve bağlantı ifadelerini öğreneceksin.`, vocab: [{ko: `전화`, tr: `telefon`, ipa: `jeon-hwa`},{ko: `휴대폰`, tr: `cep telefonu`, ipa: `hyu-dae-pon`},{ko: `인터넷`, tr: `internet`, ipa: `in-teo-net`},{ko: `와이파이`, tr: `Wi-Fi`, ipa: `wa-i-pa-i`},{ko: `비밀번호`, tr: `şifre`, ipa: `bi-mil-beon-ho`},{ko: `심카드`, tr: `SIM kart`, ipa: `shim-ka-deu`},{ko: `충전기`, tr: `şarj cihazı`, ipa: `chung-jeon-gi`},{ko: `배터리`, tr: `pil`, ipa: `bae-teo-ri`},{ko: `지도 앱`, tr: `harita uygulaması`, ipa: `ji-do aep`},{ko: `연결`, tr: `bağlantı`, ipa: `yeon-gyeol`}], phrases: [{ko: `와이파이 있어요?`, tr: `Wi-Fi var mı?`, ipa: `wa-i-pa-i i-sseo-yo`},{ko: `비밀번호가 뭐예요?`, tr: `Şifre nedir?`, ipa: `bi-mil-beon-ho-ga mwo-ye-yo`},{ko: `심카드 사고 싶어요.`, tr: `SIM kart almak istiyorum.`, ipa: `shim-ka-deu sa-go shi-peo-yo`},{ko: `충전기 있어요?`, tr: `Şarj cihazı var mı?`, ipa: `chung-jeon-gi i-sseo-yo`},{ko: `배터리가 없어요.`, tr: `Pilim yok.`, ipa: `bae-teo-ri-ga eop-seo-yo`},{ko: `인터넷이 안 돼요.`, tr: `İnternet çalışmıyor.`, ipa: `in-teo-ne-shi an dwae-yo`}], grammar: `“있어요?” var mı, “없어요” yok anlamına gelir. Teknolojiyle ilgili birçok Korece kelime İngilizceden gelir, ama Korece telaffuz farklıdır. “안 돼요” çalışmıyor veya mümkün değil anlamında kullanılabilir.`, practice: [`Wi-Fi şifresini sor.`,`SIM kart almak istediğini söyle.`,`Şarj cihazı olup olmadığını sor.`,`İnternetin çalışmadığını belirt.`,`Pilinin bittiğini söyle.`]},{day: 20, title: `Hava Durumu ve Kıyafet`, title_native: `날씨와 옷차림`, focus: `Kore’de mevsimler belirgindir; yazlar sıcak, kışlar soğuk olabilir. Bugün hava durumu ve kıyafetle ilgili temel ifadeleri öğreneceksin.`, vocab: [{ko: `날씨`, tr: `hava durumu`, ipa: `nal-ssi`},{ko: `덥다`, tr: `sıcak olmak`, ipa: `deop-da`},{ko: `춥다`, tr: `soğuk olmak`, ipa: `chup-da`},{ko: `비`, tr: `yağmur`, ipa: `bi`},{ko: `눈`, tr: `kar`, ipa: `nun`},{ko: `바람`, tr: `rüzgâr`, ipa: `ba-ram`},{ko: `우산`, tr: `şemsiye`, ipa: `u-san`},{ko: `재킷`, tr: `ceket`, ipa: `jae-kit`},{ko: `옷`, tr: `kıyafet`, ipa: `ot`},{ko: `필요하다`, tr: `gerek olmak`, ipa: `pi-ryo-ha-da`}], phrases: [{ko: `오늘 날씨가 좋아요.`, tr: `Bugün hava güzel.`, ipa: `o-neul nal-ssi-ga jo-a-yo`},{ko: `너무 더워요.`, tr: `Çok sıcak.`, ipa: `neo-mu deo-wo-yo`},{ko: `너무 추워요.`, tr: `Çok soğuk.`, ipa: `neo-mu chu-wo-yo`},{ko: `비가 와요.`, tr: `Yağmur yağıyor.`, ipa: `bi-ga wa-yo`},{ko: `우산이 필요해요.`, tr: `Şemsiyeye ihtiyacım var.`, ipa: `u-sa-ni pi-ryo-hae-yo`},{ko: `재킷이 필요해요?`, tr: `Ceket gerekli mi?`, ipa: `jae-ki-shi pi-ryo-hae-yo`}], grammar: `Hava durumunda “날씨가” çok kullanılır. “비가 와요” Korece’de kelime kelime “yağmur geliyor” gibi kurulur ama anlamı yağmur yağıyor demektir. “필요해요” ihtiyacım var veya gerekli anlamında güvenli bir seyahat kelimesidir.`, practice: [`Bugün havanın güzel olduğunu söyle.`,`Çok sıcak ve çok soğuk cümlelerini karşılaştır.`,`Yağmur yağdığını belirt.`,`Şemsiyeye ihtiyacın olduğunu söyle.`,`Ceket gerekip gerekmediğini sor.`]},{day: 21, title: `Arkadaşça Sohbet`, title_native: `친근한 대화`, focus: `Bir kafede, turda veya hostelde Koreli biriyle kısa sohbet edebilirsin. Bugün nereli olduğunu, ne sevdiğini ve basit sosyal soruları çalışacaksın.`, vocab: [{ko: `어디에서 왔어요`, tr: `nereden geldiniz`, ipa: `eo-di-e-seo wa-sseo-yo`},{ko: `취미`, tr: `hobi`, ipa: `chwi-mi`},{ko: `음악`, tr: `müzik`, ipa: `eum-ak`},{ko: `영화`, tr: `film`, ipa: `yeong-hwa`},{ko: `여행`, tr: `seyahat`, ipa: `yeo-haeng`},{ko: `좋아요`, tr: `iyi, hoş`, ipa: `jo-a-yo`},{ko: `재미있어요`, tr: `eğlenceli`, ipa: `jae-mi-i-sseo-yo`},{ko: `멋있어요`, tr: `havalı, etkileyici`, ipa: `meo-shi-sseo-yo`},{ko: `친절해요`, tr: `nazik`, ipa: `chin-jeo-rae-yo`},{ko: `같이`, tr: `birlikte`, ipa: `ga-chi`}], phrases: [{ko: `어디에서 왔어요?`, tr: `Nereden geldiniz?`, ipa: `eo-di-e-seo wa-sseo-yo`},{ko: `저는 터키에서 왔어요.`, tr: `Türkiye’den geldim.`, ipa: `co-neun teo-ki-e-seo wa-sseo-yo`},{ko: `한국이 좋아요.`, tr: `Kore hoşuma gidiyor.`, ipa: `han-gu-gi jo-a-yo`},{ko: `여행을 좋아해요.`, tr: `Seyahat etmeyi seviyorum.`, ipa: `yeo-haeng-eul jo-a-hae-yo`},{ko: `음악을 좋아해요.`, tr: `Müziği seviyorum.`, ipa: `eu-ma-geul jo-a-hae-yo`},{ko: `정말 재미있어요.`, tr: `Gerçekten eğlenceli.`, ipa: `jeong-mal jae-mi-i-sseo-yo`}], grammar: `“에서 왔어요” bir yerden geldiğini söylemek için kullanılır. “좋아해요” bir şeyi seviyorum demektir ve nesneye “을/를” eklenebilir. Sosyal konuşmalarda kısa, olumlu yorumlar iyi bir başlangıçtır.`, practice: [`Türkiye’den geldiğini söyle.`,`Karşındakine nereden geldiğini sor.`,`Seyahati sevdiğini ifade et.`,`Kore’nin hoşuna gittiğini söyle.`,`Müziği sevdiğini belirten kısa bir cümle kur.`]},{day: 22, title: `Kültürel Nezaket ve Saygı`, title_native: `문화 예절과 존중`, focus: `Kore’de yaş, hitap ve saygı dili günlük ilişkilerde önemlidir. Bugün daha nazik görünmeni sağlayacak ifadeler ve kültürel ipuçları öğreneceksin.`, vocab: [{ko: `예의`, tr: `nezaket`, ipa: `ye-ui`},{ko: `존댓말`, tr: `saygılı konuşma`, ipa: `jon-daen-mal`},{ko: `선생님`, tr: `öğretmen, saygılı hitap`, ipa: `seon-saeng-nim`},{ko: `님`, tr: `saygı eki`, ipa: `nim`},{ko: `괜찮습니다`, tr: `sorun değil`, ipa: `gwaen-chan-seum-ni-da`},{ko: `감사해요`, tr: `teşekkür ederim`, ipa: `gam-sa-hae-yo`},{ko: `죄송해요`, tr: `üzgünüm`, ipa: `joe-song-hae-yo`},{ko: `먼저`, tr: `önce`, ipa: `meon-jeo`},{ko: `기다리다`, tr: `beklemek`, ipa: `gi-da-ri-da`},{ko: `줄`, tr: `sıra`, ipa: `jul`}], phrases: [{ko: `먼저 하세요.`, tr: `Önce siz buyurun.`, ipa: `meon-jeo ha-se-yo`},{ko: `기다릴게요.`, tr: `Bekleyeceğim.`, ipa: `gi-da-ril-ge-yo`},{ko: `괜찮습니다.`, tr: `Sorun değil.`, ipa: `gwaen-chan-seum-ni-da`},{ko: `정말 감사합니다.`, tr: `Çok teşekkür ederim.`, ipa: `jeong-mal gam-sa-ham-ni-da`},{ko: `죄송해요.`, tr: `Özür dilerim.`, ipa: `joe-song-hae-yo`},{ko: `줄이 어디예요?`, tr: `Sıra nerede?`, ipa: `ju-ri eo-di-ye-yo`}], grammar: `Korece’de kibar olmak sadece kelime değil, ton ve davranış meselesidir. “하세요” kalıbı saygılı bir emir veya teklif gibi kullanılabilir. Sıraya girmek ve önce başkasına yol vermek Kore’de günlük nezaketin parçasıdır.`, practice: [`Birine “Önce siz buyurun” de.`,`Sıranın nerede olduğunu sor.`,`Çok teşekkür ettiğini ifade et.`,`Bekleyeceğini söyle.`,`“괜찮습니다” ve “괜찮아요” arasındaki resmiyet farkını düşün.`]},{day: 23, title: `Gezi Noktaları ve Biletler`, title_native: `관광지와 표`, focus: `Saray, müze, kule veya ada turu gibi yerlerde bilet ve giriş bilgisi sorman gerekir. Bugün turistik yerlerde kullanacağın ifadeleri öğreneceksin.`, vocab: [{ko: `관광지`, tr: `turistik yer`, ipa: `gwan-gwang-ji`},{ko: `궁`, tr: `saray`, ipa: `gung`},{ko: `박물관`, tr: `müze`, ipa: `bang-mul-gwan`},{ko: `전시`, tr: `sergi`, ipa: `jeon-shi`},{ko: `입장권`, tr: `giriş bileti`, ipa: `ip-jang-kkwon`},{ko: `표`, tr: `bilet`, ipa: `pyo`},{ko: `성인`, tr: `yetişkin`, ipa: `seong-in`},{ko: `어린이`, tr: `çocuk`, ipa: `eo-ri-ni`},{ko: `사진`, tr: `fotoğraf`, ipa: `sa-jin`},{ko: `금지`, tr: `yasak`, ipa: `geum-ji`}], phrases: [{ko: `입장권 하나 주세요.`, tr: `Bir giriş bileti lütfen.`, ipa: `ip-jang-kkwon ha-na ju-se-yo`},{ko: `성인 한 명이에요.`, tr: `Bir yetişkin.`, ipa: `seong-in han myeong-i-e-yo`},{ko: `사진 찍어도 돼요?`, tr: `Fotoğraf çekebilir miyim?`, ipa: `sa-jin jji-geo-do dwae-yo`},{ko: `여기는 사진 금지예요?`, tr: `Burada fotoğraf yasak mı?`, ipa: `yeo-gi-neun sa-jin geum-ji-ye-yo`},{ko: `몇 시에 닫아요?`, tr: `Saat kaçta kapanıyor?`, ipa: `myeot shi-e da-da-yo`},{ko: `가이드 투어 있어요?`, tr: `Rehberli tur var mı?`, ipa: `ga-i-deu tu-eo i-sseo-yo`}], grammar: `“찍다” fotoğraf çekmek için kullanılır. “도 돼요?” izin sorma kalıbıdır ve müze, saray, mağaza gibi yerlerde çok işine yarar. “한 명” bir kişi demektir; kişi sayısı söylerken kullanılır.`, practice: [`Bir yetişkin bileti iste.`,`Fotoğraf çekme izni sor.`,`Kapanış saatini sor.`,`Rehberli tur olup olmadığını sor.`,`“Burada fotoğraf yasak mı?” cümlesini çalış.`]},{day: 24, title: `Tren ve Şehirlerarası Yolculuk`, title_native: `기차와 도시 간 이동`, focus: `KTX ile Seul’den Busan’a veya Gyeongju’ya gitmek Kore seyahatinin klasik deneyimlerinden biridir. Bugün tren bileti ve koltukla ilgili ifadeleri öğreneceksin.`, vocab: [{ko: `기차`, tr: `tren`, ipa: `gi-cha`},{ko: `KTX`, tr: `hızlı tren`, ipa: `kei-ti-ek-seu`},{ko: `역`, tr: `istasyon`, ipa: `yeok`},{ko: `출발`, tr: `kalkış`, ipa: `chul-bal`},{ko: `도착`, tr: `varış`, ipa: `do-chak`},{ko: `좌석`, tr: `koltuk`, ipa: `jwa-seok`},{ko: `창가`, tr: `pencere kenarı`, ipa: `chang-ga`},{ko: `통로`, tr: `koridor`, ipa: `tong-no`},{ko: `편도`, tr: `tek yön`, ipa: `pyeon-do`},{ko: `왕복`, tr: `gidiş dönüş`, ipa: `wang-bok`}], phrases: [{ko: `부산행 표 주세요.`, tr: `Busan’a bilet lütfen.`, ipa: `bu-san-haeng pyo ju-se-yo`},{ko: `편도예요.`, tr: `Tek yön.`, ipa: `pyeon-do-ye-yo`},{ko: `왕복으로 주세요.`, tr: `Gidiş dönüş lütfen.`, ipa: `wang-bo-geu-ro ju-se-yo`},{ko: `창가 자리 있어요?`, tr: `Pencere kenarı yer var mı?`, ipa: `chang-ga ja-ri i-sseo-yo`},{ko: `몇 시에 출발해요?`, tr: `Saat kaçta kalkıyor?`, ipa: `myeot shi-e chul-ba-rae-yo`},{ko: `어디에서 타요?`, tr: `Nereden biniyorum?`, ipa: `eo-di-e-seo ta-yo`}], grammar: `“행” bir yere giden araç için kullanılır: “부산행” Busan yönüne giden. “자리” yer veya koltuk anlamına gelir. “에서 타요?” nereden biniyorum diye sorarken istasyon, durak veya peron için kullanılabilir.`, practice: [`Busan’a tek yön bilet iste.`,`Gidiş dönüş bilet istediğini söyle.`,`Pencere kenarı koltuk sor.`,`Trenin saat kaçta kalktığını sor.`,`Nereden bineceğini sor.`]},{day: 25, title: `Konaklama Sorunları`, title_native: `숙소 문제`, focus: `Otelde oda soğuk, Wi-Fi çalışmıyor veya havlu eksik olabilir. Bugün konaklama sorunlarını kibarca bildirmeyi öğreneceksin.`, vocab: [{ko: `문제`, tr: `sorun`, ipa: `mun-je`},{ko: `방`, tr: `oda`, ipa: `bang`},{ko: `추워요`, tr: `soğuk`, ipa: `chu-wo-yo`},{ko: `더워요`, tr: `sıcak`, ipa: `deo-wo-yo`},{ko: `수건`, tr: `havlu`, ipa: `su-geon`},{ko: `에어컨`, tr: `klima`, ipa: `e-eo-keon`},{ko: `난방`, tr: `ısıtma`, ipa: `nan-bang`},{ko: `고장`, tr: `arıza`, ipa: `go-jang`},{ko: `깨끗해요`, tr: `temiz`, ipa: `kkae-kkeu-tae-yo`},{ko: `시끄러워요`, tr: `gürültülü`, ipa: `shi-kkeu-reo-wo-yo`}], phrases: [{ko: `방에 문제가 있어요.`, tr: `Odada sorun var.`, ipa: `bang-e mun-je-ga i-sseo-yo`},{ko: `와이파이가 안 돼요.`, tr: `Wi-Fi çalışmıyor.`, ipa: `wa-i-pa-i-ga an dwae-yo`},{ko: `수건 더 주세요.`, tr: `Daha fazla havlu lütfen.`, ipa: `su-geon deo ju-se-yo`},{ko: `방이 너무 추워요.`, tr: `Oda çok soğuk.`, ipa: `bang-i neo-mu chu-wo-yo`},{ko: `에어컨이 고장 났어요.`, tr: `Klima bozuldu.`, ipa: `e-eo-keo-ni go-jang na-sseo-yo`},{ko: `방을 바꿀 수 있어요?`, tr: `Odayı değiştirebilir miyim?`, ipa: `bang-eul ba-kkul su i-sseo-yo`}], grammar: `“더” daha fazla anlamına gelir; “수건 더 주세요” çok doğal bir otel cümlesidir. “고장 났어요” bozuldu anlamına gelir ve cihazlar için kullanılır. “-ㄹ 수 있어요?” yapabilir miyim veya mümkün mü anlamı verir.`, practice: [`Odada sorun olduğunu söyle.`,`Wi-Fi’nin çalışmadığını belirt.`,`Daha fazla havlu iste.`,`Odanın çok soğuk olduğunu söyle.`,`Oda değiştirme imkânını sor.`]},{day: 26, title: `Sosyal Davetler ve Buluşma`, title_native: `초대와 약속`, focus: `Kore’de tanıştığın biriyle kahve içmek, yemek yemek veya tekrar buluşmak isteyebilirsin. Bugün davet ve buluşma ifadelerini öğreneceksin.`, vocab: [{ko: `약속`, tr: `randevu, sözleşme, buluşma`, ipa: `yak-sok`},{ko: `만나다`, tr: `buluşmak`, ipa: `man-na-da`},{ko: `같이`, tr: `birlikte`, ipa: `ga-chi`},{ko: `커피`, tr: `kahve`, ipa: `keo-pi`},{ko: `저녁`, tr: `akşam yemeği`, ipa: `jeo-nyeok`},{ko: `시간`, tr: `zaman`, ipa: `shi-gan`},{ko: `가능해요`, tr: `mümkün`, ipa: `ga-neung-hae-yo`},{ko: `바빠요`, tr: `meşgul`, ipa: `ba-ppa-yo`},{ko: `좋아요`, tr: `iyi olur`, ipa: `jo-a-yo`},{ko: `연락`, tr: `iletişim`, ipa: `yeon-rak`}], phrases: [{ko: `같이 커피 마실래요?`, tr: `Birlikte kahve içmek ister misiniz?`, ipa: `ga-chi keo-pi ma-shil-lae-yo`},{ko: `오늘 저녁 어때요?`, tr: `Bu akşam nasıl olur?`, ipa: `o-neul jeo-nyeok eo-ttae-yo`},{ko: `내일 가능해요?`, tr: `Yarın mümkün mü?`, ipa: `nae-il ga-neung-hae-yo`},{ko: `지금은 바빠요.`, tr: `Şu an meşgulüm.`, ipa: `ji-geu-meun ba-ppa-yo`},{ko: `좋아요, 만나요.`, tr: `Tamam, görüşelim.`, ipa: `jo-a-yo, man-na-yo`},{ko: `연락할게요.`, tr: `İletişime geçeceğim.`, ipa: `yeon-ra-kal-ge-yo`}], grammar: `“-ㄹ래요?” bir teklif veya istek sorusu yapar; samimi ama hâlâ kibar bir tondadır. “어때요?” nasıl olur diye plan önerirken kullanılır. “연락할게요” sonra haber vereceğim veya iletişime geçeceğim anlamındadır.`, practice: [`Birine kahve içmeyi teklif et.`,`Bu akşamın uygun olup olmadığını sor.`,`Yarın mümkün mü diye sor.`,`Şu an meşgul olduğunu söyle.`,`Görüşmeyi kabul eden kısa bir cevap ver.`]},{day: 27, title: `Duygular ve Görüş Bildirme`, title_native: `감정과 의견 말하기`, focus: `Seyahatte bir yerin güzel, eğlenceli, zor veya pahalı olduğunu söylemek sohbeti doğal hale getirir. Bugün duygularını ve basit görüşlerini ifade edeceksin.`, vocab: [{ko: `행복해요`, tr: `mutluyum`, ipa: `haeng-bo-kae-yo`},{ko: `피곤해요`, tr: `yorgunum`, ipa: `pi-go-nae-yo`},{ko: `좋아요`, tr: `iyi, hoş`, ipa: `jo-a-yo`},{ko: `싫어요`, tr: `hoş değil, istemiyorum`, ipa: `shi-reo-yo`},{ko: `예뻐요`, tr: `güzel`, ipa: `ye-ppeo-yo`},{ko: `멋있어요`, tr: `etkileyici`, ipa: `meo-shi-sseo-yo`},{ko: `어려워요`, tr: `zor`, ipa: `eo-ryeo-wo-yo`},{ko: `쉬워요`, tr: `kolay`, ipa: `shwi-wo-yo`},{ko: `재미있어요`, tr: `eğlenceli`, ipa: `jae-mi-i-sseo-yo`},{ko: `비싸요`, tr: `pahalı`, ipa: `bi-ssa-yo`}], phrases: [{ko: `정말 예뻐요.`, tr: `Gerçekten güzel.`, ipa: `jeong-mal ye-ppeo-yo`},{ko: `한국어는 어려워요.`, tr: `Korece zor.`, ipa: `han-gu-geo-neun eo-ryeo-wo-yo`},{ko: `하지만 재미있어요.`, tr: `Ama eğlenceli.`, ipa: `ha-ji-man jae-mi-i-sseo-yo`},{ko: `조금 피곤해요.`, tr: `Biraz yorgunum.`, ipa: `jo-geum pi-go-nae-yo`},{ko: `여기가 좋아요.`, tr: `Burayı seviyorum.`, ipa: `yeo-gi-ga jo-a-yo`},{ko: `너무 비싸요.`, tr: `Çok pahalı.`, ipa: `neo-mu bi-ssa-yo`}], grammar: `“정말” gerçekten, “너무” çok anlamına gelir. “하지만” ama demektir ve iki fikri bağlamak için kullanılır. “한국어는 어려워요, 하지만 재미있어요” gibi cümlelerle daha doğal konuşmaya başlarsın.`, practice: [`Korece’nin zor ama eğlenceli olduğunu söyle.`,`Bir yerin gerçekten güzel olduğunu ifade et.`,`Biraz yorgun olduğunu söyle.`,`Bir fiyatın çok pahalı olduğunu belirt.`,`Sevdiğin bir yeri “여기가 좋아요” ile anlat.`]},{day: 28, title: `Fotoğraf, Anı ve Sosyal Medya`, title_native: `사진, 추억, 소셜 미디어`, focus: `Kore’de saraylarda, kafelerde ve sokaklarda fotoğraf çekmek isteyebilirsin. Bugün fotoğraf isteme, izin sorma ve sosyal medya ifadelerini öğreneceksin.`, vocab: [{ko: `사진`, tr: `fotoğraf`, ipa: `sa-jin`},{ko: `찍다`, tr: `çekmek`, ipa: `jjik-da`},{ko: `같이`, tr: `birlikte`, ipa: `ga-chi`},{ko: `혼자`, tr: `yalnız`, ipa: `hon-ja`},{ko: `카메라`, tr: `kamera`, ipa: `ka-me-ra`},{ko: `휴대폰`, tr: `telefon`, ipa: `hyu-dae-pon`},{ko: `인스타그램`, tr: `Instagram`, ipa: `in-seu-ta-geu-raem`},{ko: `추억`, tr: `anı`, ipa: `chu-eok`},{ko: `예쁘다`, tr: `güzel olmak`, ipa: `ye-ppeu-da`},{ko: `보내다`, tr: `göndermek`, ipa: `bo-nae-da`}], phrases: [{ko: `사진 찍어 주세요.`, tr: `Fotoğrafımı çekin lütfen.`, ipa: `sa-jin jji-geo ju-se-yo`},{ko: `같이 사진 찍을래요?`, tr: `Birlikte fotoğraf çekilelim mi?`, ipa: `ga-chi sa-jin jji-geul-lae-yo`},{ko: `여기서 찍어도 돼요?`, tr: `Burada fotoğraf çekebilir miyim?`, ipa: `yeo-gi-seo jji-geo-do dwae-yo`},{ko: `휴대폰으로 찍어 주세요.`, tr: `Telefonla çekin lütfen.`, ipa: `hyu-dae-po-neu-ro jji-geo ju-se-yo`},{ko: `사진 보내 주세요.`, tr: `Fotoğrafı gönderin lütfen.`, ipa: `sa-jin bo-nae ju-se-yo`},{ko: `정말 예쁘게 나왔어요.`, tr: `Çok güzel çıktı.`, ipa: `jeong-mal ye-ppeu-ge na-wa-sseo-yo`}], grammar: `“으로/로” araç bildirir; “휴대폰으로” telefonla demektir. “찍어 주세요” çekin lütfen, “보내 주세요” gönderin lütfen gibi fiil + 주세요 kalıbı çok üretkendir. Fotoğraf izni için “찍어도 돼요?” güvenli bir kalıptır.`, practice: [`Birinden fotoğrafını çekmesini iste.`,`Fotoğraf çekme izni sor.`,`Telefonla çekmesini söyle.`,`Fotoğrafı göndermesini iste.`,`Bir fotoğrafın güzel çıktığını belirt.`]},{day: 29, title: `Seyahat Planını Anlatma`, title_native: `여행 계획 말하기`, focus: `Kore’de kaç gün kalacağını, nereye gideceğini ve ne yapmak istediğini anlatmak sosyal ve pratik durumlarda işe yarar. Bugün plan anlatma cümleleri kuracaksın.`, vocab: [{ko: `여행 계획`, tr: `seyahat planı`, ipa: `yeo-haeng gye-hoek`},{ko: `며칠`, tr: `kaç gün`, ipa: `mye-chil`},{ko: `머물다`, tr: `kalmak`, ipa: `meo-mul-da`},{ko: `가다`, tr: `gitmek`, ipa: `ga-da`},{ko: `보다`, tr: `görmek`, ipa: `bo-da`},{ko: `먹다`, tr: `yemek`, ipa: `meok-da`},{ko: `하고 싶다`, tr: `yapmak istemek`, ipa: `ha-go ship-da`},{ko: `서울`, tr: `Seul`, ipa: `seo-ul`},{ko: `부산`, tr: `Busan`, ipa: `bu-san`},{ko: `제주도`, tr: `Jeju Adası`, ipa: `je-ju-do`}], phrases: [{ko: `한국에 며칠 머물러요?`, tr: `Kore’de kaç gün kalıyorsunuz?`, ipa: `han-gu-ge mye-chil meo-mul-leo-yo`},{ko: `일주일 머물러요.`, tr: `Bir hafta kalıyorum.`, ipa: `il-ju-il meo-mul-leo-yo`},{ko: `서울에 가고 싶어요.`, tr: `Seul’e gitmek istiyorum.`, ipa: `seo-u-re ga-go shi-peo-yo`},{ko: `부산도 가고 싶어요.`, tr: `Busan’a da gitmek istiyorum.`, ipa: `bu-san-do ga-go shi-peo-yo`},{ko: `한국 음식을 먹고 싶어요.`, tr: `Kore yemeği yemek istiyorum.`, ipa: `han-guk eum-shi-geul meok-go shi-peo-yo`},{ko: `궁을 보고 싶어요.`, tr: `Sarayı görmek istiyorum.`, ipa: `gung-eul bo-go shi-peo-yo`}], grammar: `“고 싶어요” istemek anlamı verir ve fiil kökünden sonra gelir: “가고 싶어요” gitmek istiyorum. “도” de/da anlamına gelir; “부산도” Busan da demektir. Plan anlatırken kısa cümleleri arka arkaya kullanmak yeterlidir.`, practice: [`Kore’de bir hafta kaldığını söyle.`,`Seul’e gitmek istediğini ifade et.`,`Busan’a da gitmek istediğini söyle.`,`Kore yemeği yemek istediğini belirt.`,`Bir sarayı görmek istediğini söyle.`]},{day: 30, title: `Seyahat Korecesi Genel Tekrar`, title_native: `여행 한국어 총복습`, focus: `Son gün, havalimanından restorana, otelden sosyal konuşmaya kadar öğrendiklerini birleştiriyorsun. Bugün Kore’de bağımsız hareket edebilecek temel cümleleri tekrar edeceksin.`, vocab: [{ko: `안녕하세요`, tr: `merhaba`, ipa: `an-nyeong-ha-se-yo`},{ko: `감사합니다`, tr: `teşekkür ederim`, ipa: `gam-sa-ham-ni-da`},{ko: `어디예요`, tr: `nerede`, ipa: `eo-di-ye-yo`},{ko: `얼마예요`, tr: `ne kadar`, ipa: `eol-ma-ye-yo`},{ko: `주세요`, tr: `lütfen verin`, ipa: `ju-se-yo`},{ko: `가고 싶어요`, tr: `gitmek istiyorum`, ipa: `ga-go shi-peo-yo`},{ko: `먹고 싶어요`, tr: `yemek istiyorum`, ipa: `meok-go shi-peo-yo`},{ko: `도와주세요`, tr: `yardım edin lütfen`, ipa: `do-wa-ju-se-yo`},{ko: `예약했어요`, tr: `rezervasyon yaptım`, ipa: `ye-ya-kae-sseo-yo`},{ko: `괜찮아요`, tr: `sorun değil`, ipa: `gwaen-chan-a-yo`}], phrases: [{ko: `안녕하세요, 저는 터키에서 왔어요.`, tr: `Merhaba, Türkiye’den geldim.`, ipa: `an-nyeong-ha-se-yo, co-neun teo-ki-e-seo wa-sseo-yo`},{ko: `화장실이 어디예요?`, tr: `Tuvalet nerede?`, ipa: `hwa-jang-shi-ri eo-di-ye-yo`},{ko: `이거 얼마예요?`, tr: `Bu ne kadar?`, ipa: `i-geo eol-ma-ye-yo`},{ko: `이거 주세요.`, tr: `Bundan lütfen.`, ipa: `i-geo ju-se-yo`},{ko: `예약했어요.`, tr: `Rezervasyon yaptım.`, ipa: `ye-ya-kae-sseo-yo`},{ko: `도와주세요.`, tr: `Yardım edin lütfen.`, ipa: `do-wa-ju-se-yo`}], grammar: `Bu noktada en güçlü stratejin kısa, kibar ve işlevsel cümleler kurmaktır. “주세요”, “어디예요?”, “있어요?” ve “하고 싶어요” kalıplarıyla yüzlerce seyahat durumunu yönetebilirsin. Anlamadığında yavaş konuşmalarını istemek her zaman uygundur.`, practice: [`Kendini tanıt, nereden geldiğini söyle ve teşekkür et.`,`Bir kafede içecek sipariş et.`,`Otelde rezervasyon yaptığını söyle.`,`Metro istasyonunun nerede olduğunu sor.`,`Bir acil durumda yardım iste.`]}];

var CONVERSATIONS_TR_KO = [{id: 1, title: `Seul’de Kafede Sipariş`, scene: `Seul’de küçük ve kalabalık bir kafeye giriyorsun. Tezgâhtaki görevli hızlı konuşuyor, ama sen basit ve kibar cümlelerle sipariş veriyorsun.`, lines: [{who: `them`, ko: `안녕하세요, 주문하시겠어요?`, tr: `Merhaba, sipariş vermek ister misiniz?`},{who: `you`, ko: `네, 아이스 아메리카노 하나 주세요.`, tr: `Evet, bir buzlu Americano lütfen.`},{who: `them`, ko: `사이즈는 어떻게 하시겠어요?`, tr: `Boyutu nasıl olsun?`},{who: `you`, ko: `작은 사이즈로 주세요.`, tr: `Küçük boy lütfen.`},{who: `them`, ko: `여기서 드세요, 포장하세요?`, tr: `Burada mı içeceksiniz, paket mi?`},{who: `you`, ko: `여기서 마실게요.`, tr: `Burada içeceğim.`},{who: `them`, ko: `더 필요한 것 있으세요?`, tr: `Başka ihtiyacınız olan bir şey var mı?`},{who: `you`, ko: `물도 주세요.`, tr: `Su da lütfen.`},{who: `them`, ko: `네, 총 오천 원입니다.`, tr: `Evet, toplam beş bin won.`},{who: `you`, ko: `카드 돼요?`, tr: `Kart geçiyor mu?`},{who: `them`, ko: `네, 됩니다.`, tr: `Evet, geçiyor.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 2, title: `Otelde Check-in`, scene: `Busan’da otele varıyorsun ve resepsiyonda rezervasyonunu buldurmak istiyorsun. Görevli senden adını ve pasaportunu istiyor.`, lines: [{who: `them`, ko: `안녕하세요, 어떻게 도와드릴까요?`, tr: `Merhaba, size nasıl yardımcı olabilirim?`},{who: `you`, ko: `안녕하세요, 체크인하고 싶어요.`, tr: `Merhaba, check-in yapmak istiyorum.`},{who: `them`, ko: `예약하셨어요?`, tr: `Rezervasyon yaptınız mı?`},{who: `you`, ko: `네, 예약했어요.`, tr: `Evet, rezervasyon yaptım.`},{who: `them`, ko: `성함이 어떻게 되세요?`, tr: `Adınız nedir?`},{who: `you`, ko: `제 이름은 지미입니다.`, tr: `Benim adım Jimmy.`},{who: `them`, ko: `여권 보여 주세요.`, tr: `Pasaportunuzu gösterin lütfen.`},{who: `you`, ko: `네, 여기 있습니다.`, tr: `Evet, burada.`},{who: `them`, ko: `조식은 아침 일곱 시부터입니다.`, tr: `Kahvaltı sabah saat yediden itibaren.`},{who: `you`, ko: `조식이 포함돼요?`, tr: `Kahvaltı dahil mi?`},{who: `them`, ko: `네, 포함됩니다.`, tr: `Evet, dahil.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 3, title: `Yol Tarifi Sorma`, scene: `Insadong’da yürürken metro istasyonunu bulamıyorsun. Sokakta nazik görünen birine yaklaşıp kısa Koreceyle yardım istiyorsun.`, lines: [{who: `you`, ko: `실례합니다.`, tr: `Affedersiniz.`},{who: `them`, ko: `네, 말씀하세요.`, tr: `Evet, buyurun.`},{who: `you`, ko: `지하철역이 어디예요?`, tr: `Metro istasyonu nerede?`},{who: `them`, ko: `저쪽으로 똑바로 가세요.`, tr: `Şu tarafa düz gidin.`},{who: `you`, ko: `얼마나 멀어요?`, tr: `Ne kadar uzak?`},{who: `them`, ko: `걸어서 오 분 정도예요.`, tr: `Yürüyerek yaklaşık beş dakika.`},{who: `you`, ko: `오른쪽으로 가요?`, tr: `Sağa mı gidiyorum?`},{who: `them`, ko: `네, 두 번째 길에서 오른쪽으로 가세요.`, tr: `Evet, ikinci sokaktan sağa gidin.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`},{who: `them`, ko: `괜찮아요.`, tr: `Sorun değil.`},{who: `you`, ko: `좋은 하루 보내세요.`, tr: `İyi günler.`},{who: `them`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 4, title: `Restoranda Yemek Siparişi`, scene: `Jeonju’da geleneksel bir restorana giriyorsun. Menüde birçok yemek var, bu yüzden garsondan tavsiye istiyorsun ve acı olmayan bir yemek arıyorsun.`, lines: [{who: `them`, ko: `어서 오세요. 몇 분이세요?`, tr: `Hoş geldiniz. Kaç kişisiniz?`},{who: `you`, ko: `한 명이에요.`, tr: `Bir kişiyim.`},{who: `them`, ko: `여기 앉으세요.`, tr: `Buraya oturun.`},{who: `you`, ko: `메뉴 주세요.`, tr: `Menü lütfen.`},{who: `them`, ko: `네, 여기 있습니다.`, tr: `Evet, buyurun.`},{who: `you`, ko: `추천해 주세요.`, tr: `Tavsiye edin lütfen.`},{who: `them`, ko: `비빔밥이 유명해요.`, tr: `Bibimbap meşhurdur.`},{who: `you`, ko: `맵지 않게 해 주세요.`, tr: `Acı olmasın lütfen.`},{who: `them`, ko: `네, 가능합니다.`, tr: `Evet, mümkün.`},{who: `you`, ko: `물 좀 주세요.`, tr: `Biraz su lütfen.`},{who: `them`, ko: `네, 바로 드릴게요.`, tr: `Evet, hemen getireceğim.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 5, title: `KTX Tren Bileti Alma`, scene: `Seul İstasyonu’nda Busan’a gitmek için hızlı tren bileti almak istiyorsun. Gişede saat, koltuk ve bilet türü hakkında konuşuyorsun.`, lines: [{who: `them`, ko: `어디로 가세요?`, tr: `Nereye gidiyorsunuz?`},{who: `you`, ko: `부산에 가고 싶어요.`, tr: `Busan’a gitmek istiyorum.`},{who: `them`, ko: `편도예요, 왕복이에요?`, tr: `Tek yön mü, gidiş dönüş mü?`},{who: `you`, ko: `편도예요.`, tr: `Tek yön.`},{who: `them`, ko: `몇 시 기차를 원하세요?`, tr: `Saat kaç trenini istersiniz?`},{who: `you`, ko: `가장 빠른 기차 주세요.`, tr: `En erken treni lütfen.`},{who: `them`, ko: `창가 자리 괜찮으세요?`, tr: `Pencere kenarı uygun mu?`},{who: `you`, ko: `네, 좋아요.`, tr: `Evet, iyi olur.`},{who: `them`, ko: `총 오만 원입니다.`, tr: `Toplam elli bin won.`},{who: `you`, ko: `카드로 낼게요.`, tr: `Kartla ödeyeceğim.`},{who: `them`, ko: `여기 표입니다.`, tr: `İşte biletiniz.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 6, title: `Mağazada Kıyafet Alışverişi`, scene: `Myeongdong’da bir mağazada ceket beğeniyorsun. Fiyatı, bedeni ve başka renk olup olmadığını soruyorsun.`, lines: [{who: `them`, ko: `찾으시는 것 있으세요?`, tr: `Aradığınız bir şey var mı?`},{who: `you`, ko: `이 재킷 얼마예요?`, tr: `Bu ceket ne kadar?`},{who: `them`, ko: `팔만 원이에요.`, tr: `Seksen bin won.`},{who: `you`, ko: `다른 색 있어요?`, tr: `Başka renk var mı?`},{who: `them`, ko: `네, 검은색하고 파란색 있어요.`, tr: `Evet, siyah ve mavi var.`},{who: `you`, ko: `큰 사이즈 있어요?`, tr: `Büyük beden var mı?`},{who: `them`, ko: `네, 있습니다.`, tr: `Evet, var.`},{who: `you`, ko: `입어 봐도 돼요?`, tr: `Deneyebilir miyim?`},{who: `them`, ko: `물론입니다.`, tr: `Elbette.`},{who: `you`, ko: `좋아요, 이거 살게요.`, tr: `Güzel, bunu alacağım.`},{who: `them`, ko: `봉투 필요하세요?`, tr: `Poşet ister misiniz?`},{who: `you`, ko: `네, 봉투 주세요.`, tr: `Evet, poşet lütfen.`}]},{id: 7, title: `Eczanede İlaç Alma`, scene: `Kore seyahatinde başın ağrıyor ve en yakın eczaneye giriyorsun. Eczacıya belirtilerini basitçe anlatıp uygun ilaç istiyorsun.`, lines: [{who: `them`, ko: `안녕하세요, 어디가 불편하세요?`, tr: `Merhaba, nerede rahatsızlığınız var?`},{who: `you`, ko: `머리가 아파요.`, tr: `Başım ağrıyor.`},{who: `them`, ko: `열도 있어요?`, tr: `Ateşiniz de var mı?`},{who: `you`, ko: `아니요, 열은 없어요.`, tr: `Hayır, ateşim yok.`},{who: `them`, ko: `감기 증상은요?`, tr: `Soğuk algınlığı belirtisi var mı?`},{who: `you`, ko: `조금 피곤해요.`, tr: `Biraz yorgunum.`},{who: `them`, ko: `이 약을 드세요.`, tr: `Bu ilacı alın.`},{who: `you`, ko: `어떻게 먹어요?`, tr: `Nasıl kullanıyorum?`},{who: `them`, ko: `하루에 두 번 드세요.`, tr: `Günde iki kez alın.`},{who: `you`, ko: `알레르기가 있어요.`, tr: `Alerjim var.`},{who: `them`, ko: `그러면 이 약이 더 안전해요.`, tr: `O zaman bu ilaç daha güvenli.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`}]},{id: 8, title: `Yerel Biriyle Küçük Sohbet`, scene: `Busan sahilinde yürürken bir yerel kişi senin fotoğraf çektiğini fark edip sohbet başlatıyor. Kısa, samimi ve kibar Koreceyle cevap veriyorsun.`, lines: [{who: `you`, ko: `실례합니다, 사진 찍어 주세요.`, tr: `Affedersiniz, fotoğrafımı çeker misiniz?`},{who: `them`, ko: `네, 좋아요.`, tr: `Evet, olur.`},{who: `you`, ko: `감사합니다.`, tr: `Teşekkür ederim.`},{who: `them`, ko: `어디에서 왔어요?`, tr: `Nereden geldiniz?`},{who: `you`, ko: `저는 터키에서 왔어요.`, tr: `Türkiye’den geldim.`},{who: `them`, ko: `한국 여행은 어때요?`, tr: `Kore seyahati nasıl?`},{who: `you`, ko: `정말 좋아요, 음식도 맛있어요.`, tr: `Gerçekten güzel, yemekler de lezzetli.`},{who: `them`, ko: `부산도 마음에 들어요?`, tr: `Busan’ı da beğendiniz mi?`},{who: `you`, ko: `네, 바다가 정말 예뻐요.`, tr: `Evet, deniz gerçekten güzel.`},{who: `them`, ko: `한국어 잘하시네요.`, tr: `Koreceniz iyiymiş.`},{who: `you`, ko: `아니요, 조금만 해요.`, tr: `Hayır, sadece biraz konuşuyorum.`},{who: `them`, ko: `그래도 아주 좋아요.`, tr: `Yine de çok iyi.`}]}];